{"css":".rd3-page {
    font-size: 14pt;
    font-family: Helvetica, sans-serif; 
}

.rd3-page .header {
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    background-size: cover;
    background-position: 0 70%;
    height: 15em;
}

.rd3-page .header .content {
    width: 90%;
    margin: 0 auto;
    z-index: 1;
    max-width: 812px;
}

.rd3-page .header .content h1, 
.rd3-page .header .content p {
    margin: 0;
    line-height: 1.3;
    color: #f6f6f6;
}
.rd3-page .header .content h1 {
    font-size: 13pt;
    text-transform: uppercase;
    letter-spacing: 4px;
    font-weight: bold;
}

.rd3-page .header .content p {
    font-size: 32pt;
    font-weight: 200;
}

.rd3-page .header .bg-filter {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: hsla(0,0%,0%, 0.40);
}

.rd3-page .section {
    box-sizing: content-box;
}

.rd3-page .section .section-content {
    margin: 0 auto;
    width: 90%;
    max-width: 1024px;
    padding: 2em
}

.rd3-page .section .section-content h2 {
    font-weight: 600;
    line-height: 1.3;
    margin: 0;
    text-align: center;
}

.rd3-page .section .section-content p {
    line-height: 1.5;
}

.rd3-page .section .section-content .btn-list {
    list-style:none;
    padding-left: 0;
    display: flex;
    justify-content: flex-start;
    align-items: center;
}

.bg-gray-050 {
    background-color: #f6f6f6;
}

.bg-gray-000 {
    background-color: #ffffff;
}
","html":"<div class="rd3-page">
    <header class="header" style="background-image: url('/apps/molgenis-viz/img/home-header.jpg');">
        <div class="content">
            <h1>MOLGENIS-RD3</h1>
            <p>The RD3 Submitters Portal</p>
        </div>
        <div class="bg-filter" />
    </header>
    <div class="section bg-gray-050">
        <div class="section-content">
            <h2 id="section-intro-title">Overview</h2>
            <p>The <strong>RD3 Submitters Portal</strong> provides a structured format for submitting data to the RD3 database. Specifically, this portal includes templates and tables for submitting samples and experiments metadata, as well as file information if applicable.</p>
            <p>To get started, view the submitters guide and download the template.</p>
            <ul class="btn-list">
                <li><a href="../pages/#/Submit" class="btn btn-primary">Download templates</a></li>
                <li><a href="../pages/#/About" class="btn btn-link">View manual</a></li>
            </ul>
        </div>
    </div>
    <div class="section bg-gray-000">
        <div class="section-content">
            <h2>Contact</h2>
            <p class="text-center">Please contact us if you have any questions about RD3 or need help with the submission process</p>
            <div class="d-flex justify-content-center">
                <a class="btn btn-primary" href="mailto:support@molgenis.org">Email us</a>
            </div>
        </div>
    </div>
</div>","javascript":"","dependencies":{"css":[],"javascript":[]}}

