}","html":"<div class="rd3-page">
    <header class="header" style="background-image: url('/apps/molgenis-viz/img/home-header.jpg');">
        <div class="content">
            <h1>MOLGENIS-RD3</h1>
            <p>Data submission</p>
        </div>
        <div class="bg-filter" />
    </header>
    <div class="section bg-gray-050">
        <div class="section-content">
            <h2>Overview of the submission process</h2>
            <p>Before submitting data to RD3, register clinical and phenotypic metadata in PhenoStore. On a daily basis, RD3 will retrieve the latest data from PhenoStore including new submissions and updates to existing records.</p>
            <p>There are two steps for submitting sample and experiment metadata to RD3. Please see our <a href="#">data submission manual</a> for further instructions on the data submission and bulk import process.</p>
            <ol>
                <li>
                    <p><strong>Enter data into one of the RD3 templates</strong></p>
                    <p>Several templates are available for submitting data to RD3. Each template is designed for a specific samples and experiment type. Download the relevant template and enter the data that you would like to submit to RD3. Templates will have required fields and optional fields, as well as dropdown lists that contain RD3-specific values. You may import as many samples and/or experiments as you like.</p>
                </li>
                <li>
                    <p><strong>Import data into RD3</strong></p>
                    <p>After completing the template, go to the <a href="#">Upload page</a>, click the "browse" button to select your file, and click the "import" button.</p>
                    <p>Once the import process has begun, a progress page will be displayed which will show the current status. If there are any errors, the import will stop and the error message will be displayed. Correct the error(s) and repeat the process until all errors are resolved.</p>
                    <div class="alert-info p-3">
                        <span><strong>Note:</strong> Data will not be imported into RD3 if there are errors.</span>
                    </div>
                </li>
            </ol>
        </div>
    </div>
    <div class="section bg-gray-000">
        <div class="section-content">
            <h2>Download submission templates</h2>
            <form id="template-form" class="centered-form">
                <legend class="font-size-base">Which template would you like to download?</legend>
                <div class="d-flex flex-column mb-4">
                    <label for="templateSelect">Available templates</label>
                    <select id="templateSelect" class="custom-select" required>
                        <option value="" selected>---Select---</option>
                        <option value="lrGS">lrGS</option>
                        <option value="OGM">OGM</option>
                        <option value="RNA">RNA</option>
                        <option value="srDNA">srDNA</option>
                    </select>
                </div>
                <!-- <div class="mt-4">
                    <fieldset>
                        <legend class="font-size-base">Would you also like to update existing records?</legend>
                        <label>
                            <input type="radio" name="includeRecords" value="no" checked/>
                            <span>No</span>
                        </label>
                        <label>
                            <input type="radio" name="includeRecords" value="yes"/>
                            <span>Yes</span>
                        </label>
                    </fieldset>
                </div> -->
                <div class="mt-2 mb-2 d-flex align-items-center">
                    <button id="download" class="btn btn-primary" disabled>
                        Download template
                    </button>
                </div>
            </form>
            <div class="mt-4 centered-form">
                <div id="busyIndicator" class="d-none align-items-center justify-content-start">
                    <div class="spinner-border text-primary" role="status">
                        <span class="sr-only">Building template...</span>
                    </div>
                    <div class="ml-2">
                        <span class="ml-2 text-primary">Building template...</span>
                    </div>
                </div>
                <div id="errorMessage" class="d-none mt-2 alert alert-danger" role="alert">
                    <p class="m-0"><strong>Failed to build template</strong></p>
                    <span></span>
                </div>
                <div id="fileDownload" class="d-none mt-2 alert alert-success" role="alert">
                    <p class="m-0"><strong>Template built</strong>: Click the link to download the file</p>
                    <p class="m-0">Download <a id="downloadLink"></a></p>
                </div>
            </div>
        </div>
    </div>
</div>","javascript":"// set the name of script
const isEnabled = false;
const scriptName = "template builder";
const targetSchema = "rd3";


// set template mappings: the job requires schema, tables
const templates = {
    lrGS: "Samples lrGS,Experiments lrGS",
    OGM: "Samples OGM,Experiments OGM",
    RNA: "Samples RNA,Experiments RNA,Files",
    srDNA: "Samples srDNA,Experiments srDNA",
}


// get elements and set default behaviours
let selectedTemplate;
const formElem = document.getElementById("template-form");
const submitBtn = document.getElementById("download");
const selectInput = document.getElementById("templateSelect");
const fileDownloadElem = document.getElementById("fileDownload");
const fileDownloadLink = document.getElementById("downloadLink");
const busyElem = document.getElementById("busyIndicator");
const errorElem = document.getElementById("errorMessage");
const errorTextElem = errorElem.querySelector("span");

formElem.addEventListener("submit", (event) => event.preventDefault());
selectInput.addEventListener("input", (event) => {
    if (isEnabled) {
        selectedTemplate = event.target.value;
        if (selectedTemplate !== "") {
            submitBtn.removeAttribute("disabled");
        } else {
            if (!submitBtn.getAttribute("disabled")) {
                submitBtn.setAttribute("disabled", true);
            }
        }
    }
});

// start script by name
async function runScript(name, schema, tables) {
    const url = `/api/scripts/${encodeURI(name)}`;
    const response = await fetch(url, { method: "POST", body: `${schema};${tables}` });
    return response.json();
}

// check the current status of a task by url: /api/tasks/<task-id>
async function getTaskStatus(taskId) {
    const response = await fetch(`/api/tasks/${taskId}`);
    return response.json();
}

// retrieve task output
async function getTaskOutput(taskId) {
    const query = "query ($filter: JobsFilter) { Jobs(filter: $filter) { id output { id size filename extension url } } }";
    const variables = {"filter": {"id": { "equals": `${taskId}`}}}

    const response = await fetch(`/_SYSTEM_/api/graphql`, {
        method: "POST",
        body: JSON.stringify({ query: query, variables: variables })
    });
    return response.json();
}


// recheck task status: continue to check task status for n times
async function recheckTaskStatus(id, delay, retries) {
    const maxRetries = retries;
    let count = 0;
    let taskStatus = {}
    while (count < maxRetries) {
        console.log(`Checking task status ${id} (${count})`)
        try {
            const taskJson = await getTaskStatus(id);
            if (["COMPLETED", "SKIPPED", "WARNING", "ERROR", "UNKNOWN"].includes(taskJson.status)) {
                console.log('Task has finished', taskJson.status);
                count = maxRetries
                taskStatus = taskJson;
            }
            await new Promise(resolve => setTimeout(resolve, delay));
            count += 1;
        } catch (err) {
            throw new Error(err);
        }
    }
    return taskStatus;
}

submitBtn.addEventListener("click", async (event) => {
    event.preventDefault();

    // reset styles
    busyElem.classList.remove("d-none");
    busyElem.classList.add("d-flex");
    errorElem.classList.add("d-none");
    errorTextElem.innerText = "";
    fileDownloadElem.classList.add("d-none");

    try {
        console.log("Running script", scriptName);
        const result = await runScript(scriptName, schema=targetSchema, tables=templates[selectedTemplate]);

        if (result) {
            console.log("Waiting for task to complete....");
            const taskStatus = await recheckTaskStatus(result.id, 3750, 10);

            if (taskStatus) {
                console.log('Retrieving output for task', result.id);
                const taskOutput = await getTaskOutput(taskStatus.id);
                if (Object.hasOwn(taskOutput, "data")) {
                    if (Object.hasOwn(taskOutput.data, "Jobs")) {
                        const jobOutput = taskOutput.data.Jobs[0].output;
                        const filename = `${targetSchema} ${selectedTemplate}.${jobOutput.extension}`;
                        fileDownloadLink.setAttribute("href", jobOutput.url);
                        fileDownloadLink.setAttribute("download", filename);
                        fileDownloadLink.innerText = filename;
                        fileDownloadElem.classList.remove("d-none");
                    }
                }
            }
        }
    } catch(error) {
        errorTextElem.innerText = error;
        errorElem.classList.remove("d-none");
        throw new Error(error);
    } finally {
        busyElem.classList.remove("d-flex");
        busyElem.classList.add("d-none");
    }
});
